import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as s,c as a,e as i}from"./app-d308bbfa.js";const d={},r=i(`<h1 id="面试-redis" tabindex="-1"><a class="header-anchor" href="#面试-redis" aria-hidden="true">#</a> 面试-Redis</h1><h3 id="介绍一下redis" tabindex="-1"><a class="header-anchor" href="#介绍一下redis" aria-hidden="true">#</a> 介绍一下Redis</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：介绍一下Redis</b></summary><p><b style="color:#f19977;">答：Redis是一个基于Key-Value结构存储的非关系型数据库。数据类型有String、List、Set、Hash、SortedSte有序集合。其基于内存存储速度很快。使用场景有缓存、分布式锁、保存token、消息队列、延迟队列等</b></p></details><h3 id="redis是单线程还是多线程" tabindex="-1"><a class="header-anchor" href="#redis是单线程还是多线程" aria-hidden="true">#</a> Redis是单线程还是多线程</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis是单线程还是多线程</b></summary><p><b style="color:#f19977;">答：Redis6.0版本之前是核心单线程模型，所有网络IO和命令执行都由单个主线程完成；Redis6.0及以后采用多线程模型，但命令执行逻辑仍然保持单线程串行处理，仅把网络请求的读写、解析交给多IO线程分担。持久化、过期删除、后台任务也由独立后台线程处理，既保留了单线程无锁、数据安全、逻辑简单的优势，又通过多线程提升了网络高并发吞吐能力。</b></p></details><h3 id="redis和mysql如何保证一致性" tabindex="-1"><a class="header-anchor" href="#redis和mysql如何保证一致性" aria-hidden="true">#</a> Redis和MySQL如何保证一致性</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis和MySQL如何保证一致性</b></summary><p><b style="color:#f19977;">答：当程序需要读取某一个数据时，首先会先尝试去Redis里面加载，如果命中则直接返回，否则则去MySQL查询，查询到之后再把数据缓存到Redis里面。一份数据，同时保存在数据库和Redis里面，当数据发生变化的时候，需要同时更新Redis和MySQL，由于更新是有先后顺序的，并且它不像MySQL中的多表事务操作，可以满足ACID特性。所以就会出现数据一致性问题。不可能100%保证缓存和数据库一致，只能保证最终一致。解决方式有先更新数据库，再删除缓存。最后可以基于RabbitMQ的可靠性消息通信来实现最终一致性。也可以利用canal中间件，监听mysql日志，数据有变更则去更新Redis。</b></p></details><h3 id="谈谈缓存雪崩" tabindex="-1"><a class="header-anchor" href="#谈谈缓存雪崩" aria-hidden="true">#</a> 谈谈缓存雪崩</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：谈谈缓存雪崩</b></summary><p><b style="color:#f19977;">答：缓存雪崩：就是存储在缓存里面的大量数据，在同一个时刻全部过期或者Redis宕机，原本应该走缓存的大量流量全部请求到了数据库导致服务器崩溃。可以通过给过期时间加随机化偏移、做缓存预热、多级缓存、搭建集群来解决。</b></p></details><h3 id="谈谈缓存穿透" tabindex="-1"><a class="header-anchor" href="#谈谈缓存穿透" aria-hidden="true">#</a> 谈谈缓存穿透</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：谈谈缓存穿透</b></summary><p><b style="color:#f19977;">答：表示是短时间内有大量的不存在的key请求到应用里面，而这些不存在的key在缓存里面又找不到，从而全部穿透到了数据库，造成数据库压力。可以把存在的key放到布隆过滤器中，请求来时如果在布隆过滤器中查不到直接返回不走缓存也不走数据库。另外也可做接口限流、设置黑名单的方式。</b></p></details><h3 id="谈谈缓存击穿" tabindex="-1"><a class="header-anchor" href="#谈谈缓存击穿" aria-hidden="true">#</a> 谈谈缓存击穿</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：谈谈缓存击穿</b></summary><p><b style="color:#f19977;">答：给某一个key设置了过期时间，当key过期的时候，恰好这个时间点对这个key有大量并发请求过来，造成数据库压力。第一种解决方法是增加分布式锁，第一个请求过来查询缓存没有命中则获取锁并重建数据，在重建数据过程中其它请求没有获取锁只能等待重试一直到重建数据成功。第二种解决方案是对于这种热点数据不设置过期时间。</b></p></details><h3 id="介绍一下布隆过滤器" tabindex="-1"><a class="header-anchor" href="#介绍一下布隆过滤器" aria-hidden="true">#</a> 介绍一下布隆过滤器</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：介绍一下布隆过滤器</b></summary><p><b style="color:#f19977;">答：它的底层是先去初始化一个比较大的数组，存放二进制的0和1，初始时都是0，当一个key来了之后经过三次hash计算，对数组长度求模找到数组下标把数组中原来的0改为1。这样的话三个数组位置就能标明一个key的存在，查找过程也是一样的。当然也有缺点，布隆过滤器也有可能会产生一定的误判，可以设置这个误判率，一般不会超过5%。这个误判是必然存在的，想要减少误判可以增加数组长度，增加数组长度又会增大内存消耗。所以具体数组长度为多少需要根据实际考虑。5%以内的误判率一般项目也能接受，不至于高并发下压到数据库。</b></p></details><h3 id="redis实现数据持久化" tabindex="-1"><a class="header-anchor" href="#redis实现数据持久化" aria-hidden="true">#</a> Redis实现数据持久化</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis实现数据持久化</b></summary><p><b style="color:#f19977;">答：把Redis中的所有数据都记录到磁盘中，当Redis实例故障重启后，从磁盘读取快照文件，从而恢复数据。<br>也可以在Redis配置文件中开启AOF，开启之后每次写操作都会把命令记录到日志文件中。当Redis实例故障重启后，Redis会重新执行AOF文件中的所有命令，从而恢复数据。</b></p></details><h3 id="redis数据过期策略" tabindex="-1"><a class="header-anchor" href="#redis数据过期策略" aria-hidden="true">#</a> Redis数据过期策略</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis过期策略</b></summary><p><b style="color:#f19977;">答：Redis设置的数据过了有效时间，将数据从内存中删除的规则就被称之为数据的过期策略。<br>惰性删除：设置改key过期时间后，不去管，当需要该key时，检查其是否过期，如果过期则删掉。<br>定期删除：每隔一段时间，对key进行检查，删除里面过期的key(选取一定数量的key随机检查，并删除其中过期的key)<br>Redis的过期删除策略：惰性删除 + 定期删除两种策略配合使用</b></p></details><h3 id="redis数据淘汰策略" tabindex="-1"><a class="header-anchor" href="#redis数据淘汰策略" aria-hidden="true">#</a> Redis数据淘汰策略</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis数据淘汰策略</b></summary><p><b style="color:#f19977;">答：如果在Redis里面缓存过多数据，内存有限，则就需要淘汰旧数据来保存新数据。<br>不淘汰任何key，但是内存满时不允许写入新数据，默认就是这种策略<br>对设置了过期时间的key，比较key的剩余过期时间，越小的越先被淘汰<br>对全体key，随机进行淘汰<br>对设置了过期时间的key，随机进行淘汰<br>对全体key，基于LRU算法(最近最少使用)进行淘汰<br>对设置了过期时间的key，基于LRU算法(最近最少使用)进行淘汰<br>对全体key，基于LFU算法(最少频率使用)进行淘汰<br>对设置了过期时间的key，基于LFU算法(最少频率使用)进行淘汰</b></p></details><h3 id="redis分布式锁" tabindex="-1"><a class="header-anchor" href="#redis分布式锁" aria-hidden="true">#</a> Redis分布式锁</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis分布式锁</b></summary><p><b style="color:#f19977;">答：Redis实现分布式锁主要利用setnx(如果不存在则set)命令。也可直接使用Redis提供的Redisson实现分布式锁。</b></p><div class="language-sql line-numbers-mode" data-ext="sql"><pre class="language-sql"><code><span class="token comment">-- 添加锁 nx是互斥 ex是设置超时时间</span>
<span class="token keyword">set</span> <span class="token keyword">lock</span> <span class="token keyword">value</span> nx ex <span class="token number">10</span>

<span class="token comment">-- 释放锁 删除即可</span>
del <span class="token keyword">key</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div></details><h3 id="redis释放锁时需要注意的问题" tabindex="-1"><a class="header-anchor" href="#redis释放锁时需要注意的问题" aria-hidden="true">#</a> Redis释放锁时需要注意的问题</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis释放锁时需要注意的问题</b></summary><p><b style="color:#f19977;">答：要先判断当前线程是否持有这把锁，确认是自己的锁再释放，防止误删除其他线程的锁</b></p></details><h3 id="redis为什么快" tabindex="-1"><a class="header-anchor" href="#redis为什么快" aria-hidden="true">#</a> Redis为什么快</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis为什么快</b></summary><p><b style="color:#f19977;">答：Redis是纯内存操作，执行速度本来就快。另外Redis采用的是单线程避免了线程切换开销。其数据结构是基于Key-Value形式的，获取数据时间复杂度是O(1)。</b></p></details><h3 id="redis哨兵作用与原理" tabindex="-1"><a class="header-anchor" href="#redis哨兵作用与原理" aria-hidden="true">#</a> Redis哨兵作用与原理</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：Redis哨兵作用与原理</b></summary><p><b style="color:#f19977;">答：监控主从节点状态，主节点宕机自动投票选举新主库，实现故障自动转移，保证高可用</b></p></details>`,29),l=[r];function t(n,c){return s(),a("div",null,l)}const b=e(d,[["render",t],["__file","面试-Redis.html.vue"]]);export{b as default};
